<script setup lang="ts">
import{ref,onUnmounted}from'vue';import{aiApi,recognizeVoice,type TriageResult}from'../../api/ai';import{currentPatient}from'../../stores/session';import SymptomPill from'../../components/SymptomPill.vue'
const symptom=ref(''),recording=ref(false),recognizing=ref(false),analyzing=ref(false),result=ref<TriageResult|null>(null)
const tags=[{label:'头痛',icon:'◌'},{label:'发热',icon:'♨'},{label:'咳嗽',icon:'◇'},{label:'胸闷',icon:'♧'},{label:'腹痛',icon:'∽'},{label:'皮肤瘙痒',icon:'❀'},{label:'关节疼痛',icon:'+'},{label:'睡眠不佳',icon:'☾'}]
const recorder=uni.getRecorderManager()
recorder.onStop(async event=>{recording.value=false;recognizing.value=true;uni.showLoading({title:'正在识别'});try{const text=await recognizeVoice(event.tempFilePath);symptom.value=symptom.value?`${symptom.value}、${text}`:text;uni.showToast({title:'识别成功',icon:'success'})}catch(error){uni.showToast({title:error instanceof Error?error.message:'语音识别失败',icon:'none'})}finally{recognizing.value=false;uni.hideLoading()}})
recorder.onError(()=>{recording.value=false;uni.showToast({title:'录音失败，请检查麦克风权限',icon:'none'})})
function goBack(){uni.navigateBack({fail:()=>uni.reLaunch({url:'/pages/home/index'})})}
function toggleRecord(){if(recognizing.value)return;if(recording.value)recorder.stop();else uni.authorize({scope:'scope.record',success:()=>{recording.value=true;recorder.start({duration:60000,sampleRate:16000,numberOfChannels:1,encodeBitRate:48000,format:'PCM',frameSize:50})},fail:()=>uni.showModal({title:'需要麦克风权限',content:'请在小程序设置中允许使用麦克风。',showCancel:false})})}
function addTag(tag:string){symptom.value=symptom.value?`${symptom.value}、${tag}`:tag}
async function analyze(){if(!symptom.value.trim()){uni.showToast({title:'请描述您的症状',icon:'none'});return}analyzing.value=true;result.value=null;try{const data=await aiApi.triage(symptom.value.trim(),currentPatient.value?.patientId);if(data.isOutOfScope){uni.showToast({title:data.outOfScopeMessage||'请输入与健康相关的症状',icon:'none'});return}result.value=data}catch{}finally{analyzing.value=false}}
function register(){if(!result.value)return;uni.navigateTo({url:`/pages/registration/index?departmentId=${result.value.recommendedDepartmentId||''}&department=${encodeURIComponent(result.value.recommendedDepartment||'')}`})}
onUnmounted(()=>{if(recording.value)recorder.stop()})
</script>
<template><view class="triage-page"><view class="top-glow"/><view class="nav"><view class="back" @tap="goBack">‹</view><view><text>AI 智能导诊</text><text>描述症状，为您匹配合适科室</text></view></view><view class="content"><view class="assistant-card"><image src="/static/triage-robot.png" mode="aspectFill"/><view class="assistant-copy"><view class="ai-logo">AI<text>✦</text></view><view><text class="hello">您好，我是熙康导诊助手</text><text class="desc">请告诉我哪里不舒服，我会结合症状为您推荐就诊科室。</text></view></view></view><view class="panel symptom-card"><view class="panel-title"><view><text class="title-icon">≡</text><text>症状描述</text></view><text>{{symptom.length}}/300</text></view><textarea v-model="symptom" maxlength="300" placeholder="例如：我有点发烧，还有喉咙不疼……"/><view class="input-foot"><view class="voice" :class="{recording}" @tap="toggleRecord"><text class="mic">♂</text><text>{{recording?'点击结束':recognizing?'正在识别':'语音输入'}}</text></view><text @tap="symptom=''">清空</text></view></view><view class="panel common-card"><view class="section-title"><text class="heart">♡</text><text>常见症状</text></view><view class="tags"><SymptomPill v-for="item in tags" :key="item.label" :label="item.label" :icon="item.icon" @select="addTag(item.label)"/></view><button class="analyze" :loading="analyzing" @tap="analyze"><text class="bot">◉</text><text>{{analyzing?'AI 正在分析':'开始智能导诊'}}</text><text class="arrow">→</text></button></view><view v-if="result" class="panel result-card"><view class="section-title"><text class="shield">◆</text><text>推荐就诊科室</text></view><view class="department"><view class="dept-badge">{{(result.recommendedDepartment||'内科').slice(0,2)}}</view><view><view><text class="dept-name">{{result.recommendedDepartment||'综合门诊'}}</text><text class="ai-tag">AI 推荐</text></view><text class="reason">{{result.departmentReason||result.urgencyAdvice||'根据您的症状特征推荐前往该科室。'}}</text></view><view class="hospital-art"><view/><view/><view/></view></view><view class="advice"><text>就诊建议</text><text v-for="item in result.redFlags||[]" :key="item">• {{item}}</text><text v-if="result.selfCareAdvice">• {{result.selfCareAdvice}}</text></view><button class="source" @tap="register"><text>▣ 查看科室号源</text><text>›</text></button></view><view class="safe-tip">◆ AI 导诊仅提供就医方向参考，不能替代医生诊断</view></view></view></template>
