tems:center}.panel-title{justify-content:space-between}.panel-title>view{gap:10rpx;font-size:25rpx;font-weight:700}.panel-title>text{color:#8291aa;font-size:19rpx}.title-icon{width:35rpx;height:35rpx;border-radius:9rpx;background:#eaf3ff;color:#287cff;text-align:center;line-height:35rpx}.symptom-card textarea{box-sizing:border-box;width:100%;height:195rpx;margin-top:20rpx;padding:23rpx;border-radius:18rpx;background:#f5f8fc;color:#173766;font-size:23rpx;line-height:1.65}.input-foot{display:flex;align-items:center;justify-content:space-between;margin-top:15rpx;color:#637595;font-size:20rpx}.voice{padding:10rpx 18rpx;display:flex;gap:8rpx;border-radius:21rpx;background:#eaf3ff;color:#287cff}.voice.recording{background:#fff0f1;color:#ec5160}.mic{font-size:23rpx}.section-title{display:flex;align-items:center;gap:10rpx;font-size:25rpx;font-weight:700}.heart,.shield{color:#2480ff;font-size:29rpx}.tags{display:flex;flex-wrap:wrap;gap:12rpx;margin-top:20rpx}.analyze{height:82rpx;margin-top:28rpx;display:flex;align-items:center;justify-content:center;gap:15rpx;border-radius:19rpx;background:linear-gradient(105deg,#126fff,#348aff);box-shadow:0 12rpx 24rpx rgba(30,116,244,.2);color:#fff;font-size:27rpx}.bot{font-size:30rpx}.arrow{position:absolute;right:24rpx;font-size:35rpx}.result-card{padding-bottom:23rpx}.department{position:relative;margin-top:20rpx;display:flex;align-items:center;min-height:105rpx}.dept-badge{width:88rpx;height:88rpx;flex:none;border-radius:19rpx;display:flex;align-items:center;justify-content:center;background:linear-gradient(145deg,#2c86ff,#3267f4);color:#fff;font-size:29rpx;font-weight:700}.department>view:nth-child(2){width:58%;margin-left:16rpx}.department>view:nth-child(2)>view{display:flex;align-items:center;gap:10rpx}.dept-name{font-size:29rpx;font-weight:700}.ai-tag{padding:5rpx 9rpx;border-radius:10rpx;background:#dcf8ee;color:#19a780;font-size:15rpx}.reason{display:block;margin-top:8rpx;color:#73819a;font-size:18rpx;line-height:1.5}.hospital-art{position:absolute;right:2rpx;bottom:4rpx;width:105rpx;height:78rpx;display:flex;align-items:flex-end;gap:4rpx}.hospital-art view{width:29rpx;height:58rpx;border-radius:5rpx 5rpx 0 0;background:linear-gradient(#cde7ff,#edf7ff);border:1rpx solid #b7dcff}.hospital-art view:nth-child(2){height:77rpx}.hospital-art view:nth-child(2)::before{content:'+';display:block;color:#2f87fb;font-size:30rpx;text-align:center}.advice{margin-top:15rpx;padding:18rpx 20rpx;border-radius:16rpx;display:flex;flex-direction:column;gap:6rpx;background:#f5f8fc;color:#667792;font-size:18rpx}.advice text:first-child{color:#173664;font-weight:700}.source{height:70rpx;margin-top:15rpx;padding:0 20rpx;display:flex;align-items:center;justify-content:space-between;border:2rpx solid #2c80ff;border-radius:17rpx;background:#fff;color:#2477f2;font-size:22rpx;font-weight:600}.safe-tip{padding:25rpx 0 5rpx;text-align:center;color:#98a4b6;font-size:17rpx}</style>
